/* --- MIRON ABSOLUTE WIDGET --- */
.in-book-widget {
    position: absolute;
    left: 5%; width: 90%;
    background: #1a1a1a;
    border: 2px solid #42d7b8;
    border-radius: 16px;
    z-index: 2000;
    box-shadow: 0 20px 50px rgba(0,0,0,0.8);
    color: #e0e0e0;
    font-family: 'Poppins', sans-serif;
    padding: 20px;
    box-sizing: border-box;
    pointer-events: auto !important;
    display: flex; flex-direction: column;
    opacity: 0;
    transition: opacity 0.5s ease;
}
.in-book-widget.active { opacity: 1; }
.shifting-text {
    transition: bottom 0.6s cubic-bezier(0.23, 1, 0.32, 1) !important;
}
.miron-widget-header { color: #42d7b8; font-weight: 800; margin-bottom: 10px; text-align: center; font-size: 0.9em; letter-spacing: 1px; }
.miron-widget-quote { font-family: 'Newsreader', serif; font-style: italic; border-left: 3px solid #42d7b8; padding-left: 12px; margin-bottom: 15px; font-size: 1.1em; color: #fff; }
.miron-widget-actions { display: flex; gap: 10px; justify-content: center; }
.miron-widget-btn { padding: 10px 18px; border-radius: 8px; border: none; font-weight: 700; cursor: pointer; }
.miron-widget-btn.primary { background: #42d7b8; color: #000; }
.miron-widget-btn.secondary { background: #333; color: #fff; }

