ops.find_block:
win.closeMironWidget = () => {
    const widget = doc.querySelector('.in-book-widget');
    if (!widget) return;
    const page = widget.closest('.page');
    const container = page.querySelector('.text-container') || page;

    // 1. Reset all elements on the page
    doc.querySelectorAll('[data-org-bottom]').forEach(el => {
        el.style.bottom = el.dataset.orgBottom;
        el.classList.remove('shifting-text');
        delete el.dataset.orgBottom;
    });

    // 2. Reset Page height
    if (page.dataset.orgHeight) {
        page.style.height = page.dataset.orgHeight;
        delete page.dataset.orgHeight;
    }

    widget.remove();
    if (win.updateParentDims) win.updateParentDims();
};

win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;
    const range = win.lastHighlightedRange;

    // Find the physical line we clicked on to get the anchor coordinate
    let anchor = range.startContainer.parentElement;
    while (anchor && !anchor.style.bottom) anchor = anchor.parentElement;
    if (!anchor) return false;

    const SPLIT_Y = parseFloat(anchor.style.bottom);
    const GAP = 360;
    const page = anchor.closest('.page');
    if (!page) return false;

    const container = page.querySelector('.text-container') || page;

    if (doc.querySelector('.in-book-widget')) win.closeMironWidget();

    // THE PHYSICS FIX: 
    // When we elongate the page, the bottom edge moves down.
    // 1. Lines ABOVE split: Increase 'bottom' by GAP to keep them at the top.
    // 2. Lines BELOW split: Keep 'bottom' original to let them drift down with the edge.
    doc.querySelectorAll('span, div, img').forEach(el => {
        if (el.classList.contains('in-book-widget') || el.id.startsWith('pdf')) return;
        const bVal = parseFloat(el.style.bottom);
        if (!isNaN(bVal)) {
            if (!el.dataset.orgBottom) el.dataset.orgBottom = el.style.bottom;
            el.classList.add('shifting-text');

            if (bVal >= SPLIT_Y) {
                // Stay at the top
                el.style.bottom = (bVal + GAP) + 'px';
            } else {
                // Drift down with the bottom edge (so bottom value stays same)
                el.style.bottom = bVal + 'px';
            }
        }
    });

    // Elongate the canvas
    const currentH = parseFloat(page.style.height);
    if (!page.dataset.orgHeight) page.dataset.orgHeight = page.style.height;
    page.style.height = (currentH + GAP) + 'px';

    const widget = doc.createElement('div');
    widget.className = 'in-book-widget';
    widget.style.height = (GAP - 40) + 'px';
    // Position the widget exactly at the split line
    widget.style.bottom = (SPLIT_Y + 15) + 'px';

    widget.innerHTML = `
        <div class="miron-widget-header"><i class="fa-solid fa-wand-magic-sparkles"></i> MIRON INSIGHT</div>
        <div class="miron-widget-quote">"${range.toString().substring(0, 80)}..."</div>
        <div class="miron-widget-actions">
             <button class="miron-widget-btn primary">Explain Topic</button>
             <button class="miron-widget-btn secondary" onclick="window.closeMironWidget()">Dismiss</button>
        </div>
    `;

    container.appendChild(widget);
    win.CSS.highlights.clear();
    requestAnimationFrame(() => {
        widget.classList.add('active');
        if (win.updateParentDims) win.updateParentDims();
    });
    return true;
};

ops.replace_with:
win.closeMironWidget = () => {
    const widget = doc.querySelector('.in-book-widget');
    if (widget) widget.remove();
};

win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;

    // 1. Clean up existing
    win.closeMironWidget();

    const range = win.lastHighlightedRange;
    const rect = range.getBoundingClientRect();

    // Find parent container to append to
    const page = range.startContainer.parentElement.closest('.page');
    if (!page) return false;

    // 2. Create Floating Widget
    const widget = doc.createElement('div');
    widget.className = 'in-book-widget';

    // Position it some pixels below the selection rect
    // Since it's absolute, 'top' works best for overlays
    widget.style.top = (rect.bottom + 15) + 'px';

    widget.innerHTML = `
        <div class="miron-widget-header">
            <i class="fa-solid fa-wand-magic-sparkles"></i> Miron Insight
        </div>
        <div class="miron-widget-quote">
            "${range.toString().substring(0, 100)}..."
        </div>
        <div class="miron-widget-actions">
             <button class="miron-widget-btn primary">Explain</button>
             <button class="miron-widget-btn secondary" onclick="window.closeMironWidget()">Dismiss</button>
        </div>
    `;

    // Add to the page specifically so it scrolls with text
    page.appendChild(widget);

    // 3. Clear text selection highlight for better visibility
    win.CSS.highlights.clear();

    // Trigger enter animation
    requestAnimationFrame(() => {
        widget.classList.add('active');
    });

    return true;
};

