379 |         async function fetchState(force = false) {
380 |             if(!CONFIG.funcUrl) return;
381 |             try {
382 |                 if(force) document.getElementById('history-container').innerHTML = '<div style="padding:10px; text-align:center; color:var(--text-muted);">Syncing...</div>';
383 |                 
384 |                 const res = await fetch(CONFIG.funcUrl, {
385 |                     method: 'POST',
386 |                     headers: {'Content-Type': 'application/json'},
387 |                     body: JSON.stringify({ action: 'init' })
388 |                 });
389 |                 
390 |                 if(!res.ok) throw new Error("Connection failed");
391 |                 const data = await res.json();
392 |                 
393 |                 if(data.config) {
