544 |         function levenshtein(a, b) {
545 |             const matrix = [];
546 |             for (let i = 0; i <= b.length; i++) { matrix[i] = [i]; }
547 |             for (let j = 0; j <= a.length; j++) { matrix[0][j] = j; }
548 |             for (let i = 1; i <= b.length; i++) {
549 |                 for (let j = 1; j <= a.length; j++) {
550 |                     if (b.charAt(i - 1) == a.charAt(j - 1)) matrix[i][j] = matrix[i - 1][j - 1];
551 |                     else matrix[i][j] = Math.min(matrix[i - 1][j - 1] + 1, Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1));
552 |                 }
553 |             }
554 |             return matrix[b.length][a.length];
555 |         }
