557 |         function filterFiles(query) {
558 |             if (!window.repoFiles) return;
559 |             if (!query) return renderFileList(window.repoFiles);
560 |             const scored = window.repoFiles.map(file => {
561 |                 const name = file.path.split('/').pop();
562 |                 const dist = levenshtein(name.toLowerCase(), query.toLowerCase());
563 |                 const maxLen = Math.max(name.length, query.length);
564 |                 const score = Math.round((1 - dist / maxLen) * 100);
565 |                 return { ...file, score: score };
566 |             });
567 |             const filtered = scored.filter(f => f.score > 20).sort((a, b) => b.score - a.score);
568 |             renderFileList(filtered, true);
569 |         }
