// Generate nav buttons for 1-12
const s1Nav = document.getElementById('s1-nav-buttons');
for(let i=1; i<=12; i++) {
    s1Nav.innerHTML += `<button onclick="inspectFile('rare_words_${i}.txt', false)" class="flex-shrink-0 w-10 h-10 rounded-xl bg-slate-800 border border-white/5 text-[10px] font-bold text-slate-400 active:bg-sky-500/20 active:text-sky-400">${i}</button>`;
