async function inspectFile(filePath, isScript2) {
    const panel = document.getElementById('deep-stats-panel');
    panel.classList.remove('hidden');
    document.getElementById('inspect-title').innerText = isScript2 ? 'Refined Chunks' : filePath;
    document.getElementById('inspect-subtitle').innerText = isScript2 ? 'Aggregated range: 13-26' : 'Individual Source File';

    // Set loading state
    ['total-words', 'unique-words', 'unique-roots', 'success-rate', 'duplicates'].forEach(id => {
        document.getElementById(`stat-${id}`).innerText = '...';
    });

    try {
        const { data, error } = await refinery.functions.invoke('refinery-dashboard', {
            method: 'GET',
            headers: { 'Content-Type': 'application/json' },
            query: { file: filePath, is_script2: isScript2 }
        });

        if (error) throw error;

        document.getElementById('stat-total-words').innerText = data.total_words.toLocaleString();
        document.getElementById('stat-unique-words').innerText = data.unique_words.toLocaleString();
        document.getElementById('stat-unique-roots').innerText = data.unique_roots.toLocaleString();
        document.getElementById('stat-success-rate').innerText = `${data.success_rate}%`;
        document.getElementById('stat-duplicates').innerText = data.duplicates.toLocaleString();
        document.getElementById('stat-health').innerText = data.health;

        const healthDot = document.getElementById('health-indicator');
        healthDot.className = `h-2 w-2 rounded-full ${data.health === 'Healthy' ? 'bg-emerald-500' : data.health === 'Warning' ? 'bg-amber-500' : 'bg-rose-500'}`;

    } catch (err) {
        console.error(err);
    }
}

function closeInspector() {
    document.getElementById('deep-stats-panel').classList.add('hidden');
}

